// 5 API-Keys x 5 Seiten = 25 Items fuer HTTP Request Node
const apiKeys = [
  { name: 'Brantan', key: $env.DEMODESK_API_KEY_BRANTAN },
  { name: 'Amadeus', key: $env.DEMODESK_API_KEY_AMADEUS },
  { name: 'Lilian', key: $env.DEMODESK_API_KEY_LILIAN },
  { name: 'Thomas', key: $env.DEMODESK_API_KEY_THOMAS },
  { name: 'Peter', key: $env.DEMODESK_API_KEY_PETER },
].filter(k => k.key);

const maxPages = 5;
const items = [];
for (const k of apiKeys) {
  for (let page = 1; page <= maxPages; page++) {
    items.push({ json: { apiKey: k.key, userName: k.name, page } });
  }
}
return items;

// Alle Seiten-Responses verarbeiten, Recordings + Participant-Daten extrahieren
const responses = $input.all();
const initItems = $('Init API Keys').all();
const allRecordings = [];

for (let i = 0; i < responses.length; i++) {
  const resp = responses[i].json;
  const apiKey = initItems[i]?.json?.apiKey || '';
  const data = resp.data || [];
  const included = resp.included || [];

  if (!data.length) continue;

  // Maps fuer Recordings und Participants
  const recordingMap = {};
  const participantMap = {};
  for (const inc of included) {
    if (inc.type === 'recordings') {
      recordingMap[inc.id] = inc.attributes || {};
    } else if (inc.type === 'participants') {
      participantMap[inc.id] = inc.attributes || {};
    }
  }

  // Pro Demo: Recordings + Teilnehmer extrahieren
  for (const demo of data) {
    const attrs = demo.attributes || {};
    const rels = demo.relationships || {};

    const recRefs = rels.recordings?.data || [];
    for (const recRef of recRefs) {
      const rec = recordingMap[recRef.id] || {};
      if (!rec.token) continue;

      // Kunden-Teilnehmer filtern
      const partRefs = rels.participants?.data || [];
      const customers = partRefs
        .map(p => participantMap[p.id])
        .filter(p => p && p.permission === 'customer');

      const participantEmail = customers.find(p => p.email)?.email
        || customers.find(p => p.displayName?.includes('@'))?.displayName
        || '';
      const participantName = customers.find(p => p.fullName && !p.fullName.includes('@'))?.fullName || '';
      const hostName = [attrs.userFirstName, attrs.userLastName].filter(Boolean).join(' ');

      allRecordings.push({
        token: rec.token,
        demoId: demo.id,
        account: attrs.account || '',
        startDate: attrs.startDate || '',
        duration: attrs.duration || 0,
        customerUrl: rec.customerUrl || '',
        audioOnly: rec.audioOnly || false,
        includedStatus: rec.status || '',
        participantEmail,
        participantName,
        hostName,
        apiKey
      });
    }
  }
}

// Duplikate entfernen (gleicher Token)
const seen = new Set();
const unique = allRecordings.filter(r => {
  if (seen.has(r.token)) return false;
  seen.add(r.token);
  return true;
});

return [{ json: { recordings: unique, count: unique.length } }];

const allRecordings = $('Extract Recordings').first().json.recordings;

// Bestehende Demodesk-Tokens aus Supabase laden
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts?select=demodesk_token&source_type=eq.demodesk&demodesk_token=not.is.null&participant_email=not.is.null&participant_email=neq.&limit=100000',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY
  }
});

const existing = Array.isArray(response) ? response : [];
const syncedTokens = new Set(existing.filter(t => t && t.demodesk_token).map(t => t.demodesk_token));
const unprocessed = allRecordings.filter(r => !syncedTokens.has(r.token));

return [{ json: { unprocessedRecordings: unprocessed, count: unprocessed.length } }];

const recordings = $('Filter Unprocessed').first().json.unprocessedRecordings;
return recordings.map(r => ({
  json: {
    token: r.token,
    demoId: r.demoId,
    account: r.account,
    startDate: r.startDate,
    duration: r.duration,
    customerUrl: r.customerUrl || '',
    audioOnly: r.audioOnly || false,
    includedStatus: r.includedStatus || '',
    participantEmail: r.participantEmail || '',
    participantName: r.participantName || '',
    hostName: r.hostName || '',
    apiKey: r.apiKey || ''
  }
}));

// Fuer jedes Recording: Details + Transkript von Demodesk holen
const items = $input.all();
const results = [];

for (const item of items) {
  const token = item.json.token;
  const apiKey = item.json.apiKey || $env.DEMODESK_API_KEY;
  let videoUrl = '';
  let customerUrl = item.json.customerUrl || '';
  let audioOnly = item.json.audioOnly || false;
  let recordingStatus = item.json.includedStatus || '';
  let createdAt = '';

  // 1. Recording-Details abrufen (Video-URL + Metadaten)
  try {
    const recording = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://demodesk.com/api/v1/recordings/${token}`,
      headers: {
        'api-key': apiKey,
        'Accept': 'application/json'
      }
    });
    const attrs = recording.data?.attributes || {};
    videoUrl = attrs.url || '';
    customerUrl = attrs.customerUrl || customerUrl;
    audioOnly = attrs.audioOnly ?? audioOnly;
    recordingStatus = attrs.status || recordingStatus;
    createdAt = attrs.createdAt || '';
  } catch (e) {
    // Recording-Details nicht verfuegbar
  }

  // 2. Transkript abrufen
  let transcript = '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://demodesk.com/api/v1/recordings/${token}/transcript`,
      headers: {
        'api-key': apiKey,
        'Accept': 'text/plain'
      }
    });
    transcript = typeof resp === 'string' ? resp : (resp.data || JSON.stringify(resp));
  } catch (e) {
    transcript = '';
  }

  results.push({
    json: {
      token: item.json.token,
      demoId: item.json.demoId,
      account: item.json.account,
      startDate: item.json.startDate,
      duration: item.json.duration,
      participantEmail: item.json.participantEmail,
      participantName: item.json.participantName,
      hostName: item.json.hostName,
      videoUrl,
      customerUrl,
      audioOnly,
      recordingStatus,
      transcript,
      createdAt
    }
  });
}

return results;

// Daten aus Enrich Metadata + Google Drive zusammenfuehren
const enriched = $('Enrich Metadata').all();
let driveResults = [];
try {
  driveResults = $('Google Drive Upload').all();
} catch (e) {
  driveResults = [];
}

const batch = enriched.map((item, i) => {
  const meta = item.json;
  const drive = driveResults[i]?.json || {};
  const hasDrive = drive.id && !drive.error;

  return {
    source_type: 'demodesk',
    content: meta.transcript || '',
    call_type: 'strategiegespraech',
    url: meta.customerUrl || '',
    demodesk_token: meta.token || '',
    demodesk_demo_id: String(meta.demoId || ''),
    recording_url: meta.videoUrl || '',
    google_drive_url: hasDrive ? (drive.webViewLink || drive.webContentLink || '') : '',
    google_drive_file_id: hasDrive ? drive.id : '',
    customer_url: meta.customerUrl || '',
    ai_summary: '',
    audio_only: meta.audioOnly || false,
    recording_status: meta.recordingStatus || 'ready',
    participant_email: meta.participantEmail || '',
    participant_name: meta.participantName || '',
    host_name: meta.hostName || '',
    meeting_account: meta.account || '',
    meeting_start: meta.startDate || null,
    meeting_duration: meta.duration || null,
    synced_at: new Date().toISOString()
  };
});

// Upsert in Supabase (on_conflict=demodesk_token)
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: $env.SUPABASE_LEADS_URL + '/rest/v1/transcripts?on_conflict=demodesk_token',
  headers: {
    'apikey': $env.SUPABASE_LEADS_KEY,
    'Authorization': 'Bearer ' + $env.SUPABASE_LEADS_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=representation'
  },
  body: JSON.stringify(batch)
});

return [{ json: { upserted: batch.length } }];

const count = $('Filter Unprocessed').first().json.count;
const syncRunId = $('Sync Start').first().json.id;
return [{ json: { count, syncRunId } }];
